"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[6419],{6419:e=>{e.exports=JSON.parse('{"27":{"words":[{"spanish":"Me gustar\xeda reservar una habitaci\xf3n","english":"I would like to book a room"},{"spanish":"\xbfTe importar\xeda cerrar la ventana?","english":"Would you mind closing the window?"},{"spanish":"\xbfPodr\xedas explic\xe1rmelo otra vez?","english":"Could you explain it to me again?"},{"spanish":"\xbfSer\xeda posible cambiar la cita?","english":"Would it be possible to change the appointment?"},{"spanish":"Yo en tu lugar aceptar\xeda la oferta","english":"If I were you, I would accept the offer"},{"spanish":"Deber\xedas descansar un poco m\xe1s","english":"You should rest a little more"},{"spanish":"Tendr\xeda m\xe1s paciencia","english":"I would have more patience"},{"spanish":"Har\xeda una excepci\xf3n","english":"I would make an exception"},{"spanish":"Dir\xeda la verdad","english":"I would tell the truth"},{"spanish":"Querr\xeda hablar con la gerente","english":"I would like to speak with the manager"},{"spanish":"Sabr\xeda qu\xe9 hacer","english":"I would know what to do"},{"spanish":"Pondr\xeda m\xe1s atenci\xf3n","english":"I would pay more attention"},{"spanish":"Vendr\xeda m\xe1s temprano","english":"I would come earlier"},{"spanish":"Saldr\xeda despu\xe9s de almorzar","english":"I would leave after lunch"},{"spanish":"Podr\xeda ayudarte ma\xf1ana","english":"I could help you tomorrow"},{"spanish":"Nos gustar\xeda recibir m\xe1s informaci\xf3n","english":"We would like to receive more information"},{"spanish":"Ser\xeda una buena idea","english":"It would be a good idea"},{"spanish":"No me importar\xeda esperar","english":"I would not mind waiting"},{"spanish":"Preferir\xeda una mesa tranquila","english":"I would prefer a quiet table"},{"spanish":"\xbfLe molestar\xeda hablar m\xe1s despacio?","english":"Would it bother you to speak more slowly?"},{"spanish":"Deber\xedamos revisar el contrato","english":"We should review the contract"},{"spanish":"Me convendr\xeda comparar precios","english":"It would suit me to compare prices"},{"spanish":"Te recomendar\xeda llamar primero","english":"I would recommend calling first"},{"spanish":"Habr\xeda menos tr\xe1fico a esa hora","english":"There would be less traffic at that time"},{"spanish":"\xbfQuerr\xedas acompa\xf1arme?","english":"Would you like to come with me?"},{"spanish":"\xbfPodr\xedan enviarlo por correo?","english":"Could you send it by email?"},{"spanish":"La solicitud formal","english":"The formal request"},{"spanish":"La posibilidad remota","english":"The remote possibility"},{"spanish":"La propuesta alternativa","english":"The alternative proposal"},{"spanish":"El presupuesto estimado","english":"The estimated budget"},{"spanish":"La fecha tentativa","english":"The tentative date"},{"spanish":"El cambio de turno","english":"The shift change"},{"spanish":"La reuni\xf3n de seguimiento","english":"The follow-up meeting"},{"spanish":"El plan provisional","english":"The provisional plan"},{"spanish":"La soluci\xf3n pr\xe1ctica","english":"The practical solution"},{"spanish":"El permiso especial","english":"The special permission"},{"spanish":"La opini\xf3n sincera","english":"The honest opinion"},{"spanish":"El consejo \xfatil","english":"The useful advice"},{"spanish":"La disponibilidad","english":"The availability"},{"spanish":"La excepci\xf3n","english":"The exception"},{"spanish":"La confirmaci\xf3n","english":"The confirmation"},{"spanish":"La cortes\xeda profesional","english":"Professional courtesy"}],"conversations":[{"id":1,"topic":"Reserva de hotel para un congreso","dialog":[{"speaker":"Elena","spanish":"Buenos d\xedas. Me gustar\xeda reservar una habitaci\xf3n individual para la pr\xf3xima semana, si todav\xeda quedaran plazas.","english":"Good morning. I would like to book a single room for next week, if there were still spots available."},{"speaker":"Javier","spanish":"Claro, se\xf1ora. Tendr\xedamos disponibilidad de martes a viernes. \xbfPreferir\xeda una habitaci\xf3n tranquila o una con vista a la avenida?","english":"Of course, ma\'am. We would have availability from Tuesday to Friday. Would you prefer a quiet room or one facing the avenue?"},{"speaker":"Elena","spanish":"Preferir\xeda una tranquila, porque tendr\xeda que preparar una presentaci\xf3n por la noche. \xbfSer\xeda posible incluir desayuno temprano?","english":"I would prefer a quiet one because I would have to prepare a presentation at night. Would it be possible to include an early breakfast?"},{"speaker":"Javier","spanish":"S\xed, podr\xedamos servirlo desde las seis y media. Tambi\xe9n le dir\xeda que la tarifa baja si confirma hoy.","english":"Yes, we could serve it from six thirty. I should also tell you that the rate goes down if you confirm today."},{"speaker":"Elena","spanish":"Perfecto. \xbfLe importar\xeda enviarme la confirmaci\xf3n por correo y a\xf1adir una mesa de trabajo?","english":"Perfect. Would you mind sending me the confirmation by email and adding a work desk?"},{"speaker":"Javier","spanish":"Con mucho gusto. Yo pondr\xeda esa nota ahora mismo y le mandar\xeda todos los detalles en unos minutos.","english":"With pleasure. I would add that note right away and send you all the details in a few minutes."}],"questions":[{"question":"\xbfPor qu\xe9 Elena prefiere una habitaci\xf3n tranquila?","options":["Porque quiere dormir hasta tarde","Porque tendr\xeda que preparar una presentaci\xf3n por la noche","Porque no le gusta la avenida","Porque viajar\xeda con ni\xf1os"],"answerIndex":1,"answer":"Porque tendr\xeda que preparar una presentaci\xf3n por la noche"},{"question":"\xbfQu\xe9 ventaja menciona Javier si Elena confirma hoy?","options":["Le incluir\xedan una cena gratis","La tarifa bajar\xeda","Podr\xeda cancelar sin costo","Recibir\xeda una habitaci\xf3n m\xe1s grande"],"answerIndex":1,"answer":"La tarifa bajar\xeda"},{"question":"\xbfQu\xe9 quiere a\xf1adir Elena a la habitaci\xf3n?","options":["Una cafetera adicional","Una mesa de trabajo","Un sof\xe1 cama","Un balc\xf3n"],"answerIndex":1,"answer":"Una mesa de trabajo"}]},{"id":2,"topic":"Consejos laborales despu\xe9s de una entrevista","dialog":[{"speaker":"Marta","spanish":"La entrevista sali\xf3 bien, pero no s\xe9 si aceptar\xedan mi propuesta de horario flexible.","english":"The interview went well, but I do not know whether they would accept my proposal for a flexible schedule."},{"speaker":"Carlos","spanish":"Yo en tu lugar les escribir\xeda hoy mismo. Dir\xeda que podr\xedas empezar antes y salir a media tarde sin afectar el trabajo.","english":"If I were you, I would write to them today. I would say that you could start earlier and leave in mid-afternoon without affecting the work."},{"speaker":"Marta","spanish":"Tienes raz\xf3n. Tambi\xe9n me gustar\xeda preguntar si ser\xeda posible trabajar desde casa dos d\xedas por semana.","english":"You are right. I would also like to ask whether it would be possible to work from home two days a week."},{"speaker":"Carlos","spanish":"Deber\xedas hacerlo con un tono claro y profesional. Incluso podr\xedas mencionar que ya has coordinado equipos a distancia.","english":"You should do it in a clear and professional tone. You could even mention that you have already coordinated remote teams."},{"speaker":"Marta","spanish":"\xbfCrees que sonar\xeda exigente? No querr\xeda perder la oportunidad por pedir demasiado.","english":"Do you think it would sound demanding? I would not want to lose the opportunity by asking for too much."},{"speaker":"Carlos","spanish":"Al contrario. Si lo plantearas con cortes\xeda, pensar\xedan que sabes organizarte y valorar\xedan tu honestidad.","english":"On the contrary. If you framed it politely, they would think you know how to organize yourself and would value your honesty."}],"questions":[{"question":"\xbfQu\xe9 teme Marta al escribir despu\xe9s de la entrevista?","options":["Parecer demasiado exigente","Olvidar la direcci\xf3n de correo","Llegar tarde a la oficina","Perder sus documentos"],"answerIndex":0,"answer":"Parecer demasiado exigente"},{"question":"\xbfQu\xe9 modalidad quiere pedir Marta adem\xe1s del horario flexible?","options":["Un aumento inmediato","Trabajar desde casa dos d\xedas por semana","Un traslado internacional","Un curso de idiomas"],"answerIndex":1,"answer":"Trabajar desde casa dos d\xedas por semana"},{"question":"\xbfQu\xe9 experiencia le aconseja mencionar Carlos?","options":["Que ha viajado mucho por trabajo","Que ha estudiado administraci\xf3n","Que ya ha coordinado equipos a distancia","Que conoce al director"],"answerIndex":2,"answer":"Que ya ha coordinado equipos a distancia"}]},{"id":3,"topic":"Planificaci\xf3n de una feria vecinal","dialog":[{"speaker":"Sof\xeda","spanish":"Para la feria del barrio, me gustar\xeda invitar a artesanos locales y montar un escenario peque\xf1o en la plaza.","english":"For the neighborhood fair, I would like to invite local artisans and set up a small stage in the square."},{"speaker":"Diego","spanish":"Ser\xeda una propuesta atractiva, pero tendr\xedamos que pedir permiso al ayuntamiento y revisar el presupuesto.","english":"That would be an attractive proposal, but we would have to ask city hall for permission and review the budget."},{"speaker":"Sof\xeda","spanish":"Claro. \xbfPodr\xedas encargarte t\xfa de hablar con cultura? Yo pondr\xeda por escrito el plan provisional y buscar\xeda patrocinadores.","english":"Of course. Could you take charge of speaking with the cultural office? I would put the provisional plan in writing and look for sponsors."},{"speaker":"Diego","spanish":"S\xed, y yo te recomendar\xeda reservar tambi\xe9n una carpa por si lloviera. Habr\xeda menos problemas con el sonido.","english":"Yes, and I would also recommend reserving a tent in case it rained. There would be fewer problems with the sound."},{"speaker":"Sof\xeda","spanish":"Buena idea. Adem\xe1s, querr\xeda que hubiera un espacio para ni\xf1os y otro para comida saludable.","english":"Good idea. I would also want there to be one area for children and another for healthy food."},{"speaker":"Diego","spanish":"Entonces vendr\xeda bien reunir al comit\xe9 ma\xf1ana; as\xed decidir\xedamos qu\xe9 proveedores podr\xedan participar.","english":"Then it would be good to gather the committee tomorrow; that way we would decide which suppliers could take part."}],"questions":[{"question":"\xbfPara qu\xe9 recomienda Diego reservar una carpa?","options":["Para invitar a m\xe1s m\xfasicos","Para evitar problemas si llueve","Para vender entradas m\xe1s caras","Para decorar la plaza"],"answerIndex":1,"answer":"Para evitar problemas si llueve"},{"question":"\xbfQu\xe9 tarea asume Sof\xeda en la organizaci\xf3n?","options":["Poner por escrito el plan y buscar patrocinadores","Dise\xf1ar los carteles y limpiar la plaza","Contratar a todos los proveedores","Organizar el transporte de los vecinos"],"answerIndex":0,"answer":"Poner por escrito el plan y buscar patrocinadores"},{"question":"\xbfQu\xe9 decidir\xeda el comit\xe9 al reunirse?","options":["Qui\xe9n viajar\xeda al extranjero","Qu\xe9 proveedores podr\xedan participar","D\xf3nde se abrir\xeda un museo","Cu\xe1ndo cambiar\xeda el alcalde"],"answerIndex":1,"answer":"Qu\xe9 proveedores podr\xedan participar"}]},{"id":4,"topic":"Petici\xf3n en un restaurante por una alergia","dialog":[{"speaker":"Luc\xeda","spanish":"Buenas noches. Me gustar\xeda cenar aqu\xed, pero tengo alergia a las nueces y querr\xeda revisar los ingredientes con calma.","english":"Good evening. I would like to have dinner here, but I am allergic to nuts and I would like to review the ingredients carefully."},{"speaker":"Tom\xe1s","spanish":"Por supuesto. \xbfLe molestar\xeda si le trajera la carta especial de al\xe9rgenos? As\xed podr\xeda elegir con m\xe1s seguridad.","english":"Of course. Would it bother you if I brought you the special allergen menu? That way you could choose more safely."},{"speaker":"Luc\xeda","spanish":"Se lo agradecer\xeda mucho. Tambi\xe9n preferir\xeda un plato que no llevara crema, porque cenar\xeda algo m\xe1s ligero.","english":"I would appreciate it very much. I would also prefer a dish without cream because I would eat something lighter."},{"speaker":"Tom\xe1s","spanish":"En ese caso, le recomendar\xeda el pescado a la plancha. Ser\xeda posible cambiar la salsa por verduras salteadas.","english":"In that case, I would recommend the grilled fish. It would be possible to swap the sauce for saut\xe9ed vegetables."},{"speaker":"Luc\xeda","spanish":"Perfecto. \xbfY le importar\xeda pedir en cocina que usaran utensilios limpios? No me arriesgar\xeda a una contaminaci\xf3n cruzada.","english":"Perfect. And would you mind asking the kitchen to use clean utensils? I would not take the risk of cross-contamination."},{"speaker":"Tom\xe1s","spanish":"Claro que no. Yo pondr\xeda una nota urgente en el pedido y luego vendr\xeda a confirmarle todo antes de servirlo.","english":"Of course not. I would put an urgent note on the order and then come back to confirm everything before serving it."}],"questions":[{"question":"\xbfPor qu\xe9 Luc\xeda quiere revisar los ingredientes?","options":["Porque no ha comido en todo el d\xeda","Porque busca el plato m\xe1s barato","Porque tiene alergia a las nueces","Porque no entiende la carta"],"answerIndex":2,"answer":"Porque tiene alergia a las nueces"},{"question":"\xbfQu\xe9 plato le recomienda Tom\xe1s?","options":["Una sopa con crema","El pescado a la plancha","Una pasta con nueces","Una hamburguesa doble"],"answerIndex":1,"answer":"El pescado a la plancha"},{"question":"\xbfQu\xe9 precauci\xf3n extra pide Luc\xeda?","options":["Que le guarden una mesa junto a la ventana","Que le traigan agua sin hielo","Que usen utensilios limpios en la cocina","Que le preparen el postre primero"],"answerIndex":2,"answer":"Que usen utensilios limpios en la cocina"}]}],"stories":[{"id":1,"title":"Una petici\xf3n bien escrita","sentences":[{"spanish":"Antes de escribir al director del m\xe1ster, Luc\xeda hizo una lista de todo lo que le gustar\xeda pedir con cortes\xeda.","english":"Before writing to the master\u2019s program director, Luc\xeda made a list of everything she would like to request politely."},{"spanish":"En su correo explic\xf3 que querr\xeda aplazar la matr\xedcula una semana, porque su banco todav\xeda no hab\xeda procesado la transferencia.","english":"In her email, she explained that she would like to postpone enrollment for one week because her bank had still not processed the transfer."},{"spanish":"Tambi\xe9n pregunt\xf3 si ser\xeda posible asistir a las primeras clases en l\xednea, ya que vendr\xeda desde otra ciudad.","english":"She also asked whether it would be possible to attend the first classes online, since she would be coming from another city."},{"spanish":"Un amigo le dijo que deber\xeda sonar firme pero agradecida, y que \xe9l en su lugar a\xf1adir\xeda los documentos adjuntos desde el principio.","english":"A friend told her she should sound firm but grateful, and that he, in her place, would attach the documents from the start."},{"spanish":"Luc\xeda reley\xf3 el mensaje y cambi\xf3 varias frases para que sonaran m\xe1s claras y profesionales.","english":"Luc\xeda reread the message and changed several phrases so they would sound clearer and more professional."},{"spanish":"Al final, el director respondi\xf3 que podr\xedan ayudarla y que le mandar\xedan una soluci\xf3n provisional esa misma tarde.","english":"In the end, the director replied that they could help her and would send her a provisional solution that very afternoon."}]},{"id":2,"title":"El viaje provisional de Nora","sentences":[{"spanish":"Nora quer\xeda organizar un retiro corto para su equipo y pens\xf3 que ser\xeda mejor hacerlo cerca del mar.","english":"Nora wanted to organize a short retreat for her team and thought it would be better to do it near the sea."},{"spanish":"Les dijo que preferir\xeda viajar en tren, porque as\xed todos podr\xedan trabajar o descansar durante el trayecto.","english":"She told them she would prefer to travel by train because that way everyone could work or rest during the trip."},{"spanish":"Su compa\xf1era Irene respondi\xf3 que reservar\xeda el hotel si Nora le enviaba una lista con tres opciones claras.","english":"Her coworker Irene replied that she would book the hotel if Nora sent her a list with three clear options."},{"spanish":"Otro colega coment\xf3 que pondr\xeda una actividad al aire libre solo si el pron\xf3stico siguiera estable.","english":"Another colleague commented that he would schedule an outdoor activity only if the forecast stayed stable."},{"spanish":"Para Nora, lo ideal ser\xeda que cada persona eligiera entre una caminata, un taller creativo o una sesi\xf3n tranquila de planificaci\xf3n.","english":"For Nora, the ideal would be for each person to choose between a walk, a creative workshop, or a quiet planning session."},{"spanish":"Aunque el plan todav\xeda era tentativo, todos coincidieron en que ese viaje mejorar\xeda el ambiente del equipo.","english":"Even though the plan was still tentative, everyone agreed that the trip would improve the team\u2019s atmosphere."}]},{"id":3,"title":"Consejos antes de mudarte","sentences":[{"spanish":"Cuando \xc1lvaro recibi\xf3 una oferta en otra ciudad, pidi\xf3 consejo a su hermana mayor.","english":"When \xc1lvaro received an offer in another city, he asked his older sister for advice."},{"spanish":"Ella le dijo que, en su lugar, buscar\xeda un piso cerca del transporte p\xfablico y leer\xeda cada cl\xe1usula del contrato.","english":"She told him that, in his place, she would look for an apartment near public transportation and would read every clause of the contract."},{"spanish":"Tambi\xe9n le recomend\xf3 que no firmara nada sin comparar precios, porque despu\xe9s se arrepentir\xeda.","english":"She also recommended that he not sign anything without comparing prices, because afterward he would regret it."},{"spanish":"\xc1lvaro respondi\xf3 que le gustar\xeda vivir solo, pero que aceptar\xeda compartir apartamento si as\xed tuviera m\xe1s margen para ahorrar.","english":"\xc1lvaro replied that he would like to live alone, but that he would accept sharing an apartment if that gave him more room to save money."},{"spanish":"Su hermana a\xf1adi\xf3 que incluso saldr\xeda m\xe1s barato comprar algunos muebles de segunda mano al principio.","english":"His sister added that it would even be cheaper to buy some secondhand furniture at first."},{"spanish":"Gracias a esa conversaci\xf3n, \xc1lvaro tom\xf3 decisiones m\xe1s pr\xe1cticas y evit\xf3 varios gastos innecesarios.","english":"Thanks to that conversation, \xc1lvaro made more practical decisions and avoided several unnecessary expenses."}]}],"speaking":{"title":"Peticiones, consejos y planes hipot\xe9ticos","description":"Practica c\xf3mo hacer solicitudes corteses, dar consejos y hablar de posibilidades con el condicional.","questions_and_answers":[{"question":{"spanish":"\xbfC\xf3mo pedir\xedas una mesa m\xe1s tranquila en un restaurante?","english":"How would you ask for a quieter table in a restaurant?"},"answer":{"spanish":"Preferir\xeda una mesa m\xe1s tranquila, por favor.","english":"I would prefer a quieter table, please."}},{"question":{"spanish":"\xbfQu\xe9 dir\xedas para solicitar m\xe1s tiempo para un informe?","english":"What would you say to ask for more time for a report?"},"answer":{"spanish":"Me gustar\xeda pedir un d\xeda m\xe1s para terminar el informe.","english":"I would like to ask for one more day to finish the report."}},{"question":{"spanish":"\xbfC\xf3mo ofrecer\xedas ayuda a una compa\xf1era?","english":"How would you offer help to a coworker?"},"answer":{"spanish":"Podr\xeda ayudarte con la presentaci\xf3n ma\xf1ana por la tarde.","english":"I could help you with the presentation tomorrow afternoon."}},{"question":{"spanish":"\xbfQu\xe9 consejo dar\xedas a alguien que est\xe1 agotado?","english":"What advice would you give to someone who is exhausted?"},"answer":{"spanish":"Yo en tu lugar descansar\xeda esta noche y reorganizar\xeda todo ma\xf1ana.","english":"If I were you, I would rest tonight and reorganize tomorrow."}},{"question":{"spanish":"\xbfC\xf3mo preguntar\xedas si pueden cambiar una cita?","english":"How would you ask whether they can change an appointment?"},"answer":{"spanish":"\xbfSer\xeda posible cambiar la cita para el jueves?","english":"Would it be possible to change the appointment to Thursday?"}},{"question":{"spanish":"\xbfQu\xe9 dir\xedas para pedir que hablen m\xe1s despacio?","english":"What would you say to ask someone to speak more slowly?"},"answer":{"spanish":"\xbfLe importar\xeda hablar un poco m\xe1s despacio?","english":"Would you mind speaking a little more slowly?"}},{"question":{"spanish":"\xbfC\xf3mo explicar\xedas una preferencia de viaje?","english":"How would you explain a travel preference?"},"answer":{"spanish":"Preferir\xeda salir temprano para evitar el tr\xe1fico.","english":"I would prefer to leave early to avoid traffic."}},{"question":{"spanish":"\xbfQu\xe9 dir\xedas al gerente si quieres m\xe1s informaci\xf3n?","english":"What would you say to the manager if you wanted more information?"},"answer":{"spanish":"Querr\xeda recibir m\xe1s detalles antes de firmar.","english":"I would like to receive more details before signing."}},{"question":{"spanish":"\xbfC\xf3mo recomendar\xedas una opci\xf3n m\xe1s barata?","english":"How would you recommend a cheaper option?"},"answer":{"spanish":"Yo elegir\xeda la opci\xf3n mensual porque costar\xeda menos.","english":"I would choose the monthly option because it would cost less."}},{"question":{"spanish":"\xbfQu\xe9 dir\xedas para pedir una excepci\xf3n?","english":"What would you say to ask for an exception?"},"answer":{"spanish":"\xbfPodr\xeda hacer una excepci\xf3n en mi caso, por favor?","english":"Could you make an exception in my case, please?"}},{"question":{"spanish":"\xbfC\xf3mo hablar\xedas de una posibilidad \xfatil para una reuni\xf3n?","english":"How would you talk about a useful possibility for a meeting?"},"answer":{"spanish":"Podr\xedamos reunirnos en l\xednea si nadie pudiera venir en persona.","english":"We could meet online if nobody could come in person."}},{"question":{"spanish":"\xbfQu\xe9 consejo dar\xedas sobre un contrato?","english":"What advice would you give about a contract?"},"answer":{"spanish":"Deber\xedas revisar el contrato con calma antes de aceptarlo.","english":"You should review the contract carefully before accepting it."}},{"question":{"spanish":"\xbfC\xf3mo pedir\xedas que te env\xeden algo por correo?","english":"How would you ask them to send you something by email?"},"answer":{"spanish":"\xbfPodr\xedan envi\xe1rmelo por correo hoy mismo?","english":"Could you email it to me today?"}},{"question":{"spanish":"\xbfQu\xe9 dir\xedas si quisieras agradecer una propuesta?","english":"What would you say if you wanted to appreciate a proposal?"},"answer":{"spanish":"Dir\xeda que la propuesta ser\xeda muy \xfatil para el equipo.","english":"I would say that the proposal would be very useful for the team."}},{"question":{"spanish":"\xbfC\xf3mo expresar\xedas un deseo profesional?","english":"How would you express a professional wish?"},"answer":{"spanish":"Me gustar\xeda coordinar un proyecto internacional el pr\xf3ximo a\xf1o.","english":"I would like to coordinate an international project next year."}},{"question":{"spanish":"\xbfQu\xe9 har\xedas para resolver un retraso importante?","english":"What would you do to solve an important delay?"},"answer":{"spanish":"Yo llamar\xeda primero y luego pondr\xeda la queja por escrito.","english":"I would call first and then put the complaint in writing."}},{"question":{"spanish":"\xbfC\xf3mo pedir\xedas un plato sin crema?","english":"How would you ask for a dish without cream?"},"answer":{"spanish":"Preferir\xeda un plato sin crema, si fuera posible.","english":"I would prefer a dish without cream, if possible."}},{"question":{"spanish":"\xbfQu\xe9 dir\xedas si quisieras cambiar de turno?","english":"What would you say if you wanted to change shifts?"},"answer":{"spanish":"Querr\xeda cambiar de turno porque tengo una cita m\xe9dica.","english":"I would like to change shifts because I have a medical appointment."}},{"question":{"spanish":"\xbfC\xf3mo sonar\xedas diplom\xe1tico al discrepar?","english":"How would you sound diplomatic when disagreeing?"},"answer":{"spanish":"Yo dir\xeda la verdad, pero la explicar\xeda con tacto.","english":"I would tell the truth, but I would explain it tactfully."}},{"question":{"spanish":"\xbfQu\xe9 sugerir\xedas para una feria barrial?","english":"What would you suggest for a neighborhood fair?"},"answer":{"spanish":"Ser\xeda buena idea invitar a m\xe1s artesanos locales.","english":"It would be a good idea to invite more local artisans."}}]}}}')}}]);